from flask import Flask, render_template, request, redirect, url_for, flash
from database import db, init_db
from models import URL
import string
import random

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///urls.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
app.config['SECRET_KEY'] = 'secret_key'

init_db(app)

def generate_short_url(length=6):
    chars = string.ascii_letters + string.digits
    while True:
        short_url = ''.join(random.choice(chars) for _ in range(length))
        if not URL.query.filter_by(short_id=short_url).first():
            return short_url

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        original_url = request.form.get('url')
        if not original_url:
            flash('URL is required!')
            return redirect(url_for('index'))

        url_entry = URL.query.filter_by(original_url=original_url).first()
        if url_entry:
            short_url = url_entry.short_id
        else:
            short_url = generate_short_url()
            new_url = URL(original_url=original_url, short_id=short_url)
            db.session.add(new_url)
            db.session.commit()

        return render_template('index.html', short_url=request.host_url + short_id)

    return render_template('index.html')

@app.route('/<short_id>')
def redirect_to_url(short_id):
    url_entry = URL.query.filter_by(short_id=short_id).first_or_404()
    return redirect(url_entry.original_url)

if __name__ == '__main__':
    app.run(debug=True)
